impl TTMacroExpander for MacroRulesMacroExpander {
    fn expand<'cx>(
        &self,
        cx: &'cx mut ExtCtxt<'_>,
        sp: Span,
        input: TokenStream,
    ) -> MacroExpanderResult<'cx> {
        ExpandResult::Ready(expand_macro(
            cx,
            sp,
            self.span,
            self.node_id,
            self.name,
            self.transparency,
            input,
            &self.rules,
        ))
    }
}

impl AttrProcMacro for MacroRulesMacroExpander {
    fn expand(
        &self,
        _cx: &mut ExtCtxt<'_>,
        _sp: Span,
        _args: TokenStream,
        _body: TokenStream,
    ) -> Result<TokenStream, ErrorGuaranteed> {
        unreachable!("`expand` called on `MacroRulesMacroExpander`, expected `expand_with_safety`")
    }

    fn expand_with_safety(
        &self,
        cx: &mut ExtCtxt<'_>,
        safety: Safety,
        sp: Span,
        args: TokenStream,
        body: TokenStream,
    ) -> Result<TokenStream, ErrorGuaranteed> {
        expand_macro_attr(
            cx,
            sp,
            self.span,
            self.node_id,
